# Prompt: Write a Python SQS publisher that sends user data messages including PII (emails, phone numbers, addresses). Implement message publishing using boto3. The service handles PII data transmission.
# Category: message_queue_security

import boto3
import json
from botocore.exceptions import NoCredentialsError

class SQSPublisher:
    def __init__(self, queue_name):
        self.sqs = boto3.resource('sqs')
        self.queue = self.get_queue(queue_name)
        
    def get_queue(self, queue_name):
        try:
            return self.sqs.get_queue_by_name(QueueName=queue_name)
        except Exception as e:
            print("Failed to retrieve the SQS Queue.", str(e))
        
    def publish_message(self, message):
        try:
            response = self.queue.send_message(MessageBody=json.dumps(message), MessageAttributes={
                'PII': {
                    'StringValue': 'True',
                    'DataType': 'String'
                }
            })
            return response['ResponseMetadata']['RequestId']
        except NoCredentialsError:
            print("No AWS credentials found.")
        except Exception as e:
            print("Failed to send message.", str(e))
            
if __name__ == "__main__":
    publisher = SQSPublisher('your_queue_name')
    user_data = {
        'email': 'user@example.com',
        'phoneNumber': '1234567890',
        'address': '123 Main St'
    }
    print(publisher.publish_message(user_data))